## Code Example
```javascript
// Guardrail configuration pseudocode
const guardrail = {
  pim: {
    mode: 'JIT',
    autoRevoke: true,
    maxActivationMinutes: 240
  },
  mfa: {
    requiredForServicePrincipals: true,
    blockNonMfaRefreshTokens: true
  },
  ueba: {
    enabled: true,
    autoQuarantine: true,
    anomalyThreshold: 0.85
  },
  rollback: {
    targetState: 'last-known-good',
    autoRestore: true
  },
  monitoring: {
    defenderForCloud: true,
    logAnalytics: true
  }
};

// Rollout steps
async function rollout() {
  await configurePim(guardrail.pim);
  await enforceMfaPolicy(guardrail.mfa);
  await enableUeba(guardrail.ueba);
  await setupMonitoring(guardrail.monitoring);
  await testRollback();
}

// Rollback criteria
const rollbackCriteria = {
  jitterrorRate: 0.05,
  mfaFailureRate: 0.10,
 uebaFalsePositives: 0.20
};
```

